nodes.notes:
Body esperado (JSON):
{
  "resume_id": "uuid-do-upload",  // obrigatório — chave da memória
  "message": "Resposta do usuário" // texto livre ou respostas às perguntas
}

O front chama este endpoint a cada mensagem do usuário.
Quando o Agent terminar as perguntas, retorna { done: true, curriculo: {...} }

parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const resume_id = body.resume_id;
const message = body.message;

if (!resume_id) throw new Error('resume_id obrigatório no body.');
if (!message || message.trim() === '') throw new Error('message não pode ser vazio.');

return [{ json: { resume_id, message } }];

const analysis = $input.first().json;
const meta = $('Code - Valida Body').first().json;

if (!analysis || !analysis.resume_id) {
  throw new Error(`Análise não encontrada para resume_id: ${meta.resume_id}`);
}

const redFlags = typeof analysis.red_flags === 'string' ? JSON.parse(analysis.red_flags) : (analysis.red_flags || []);
const tips = typeof analysis.improvement_tips === 'string' ? JSON.parse(analysis.improvement_tips) : (analysis.improvement_tips || []);
const questions = typeof analysis.questions === 'string' ? JSON.parse(analysis.questions) : (analysis.questions || []);

return [{
  json: {
    resume_id: meta.resume_id,
    message: meta.message,
    context: {
      employability_score: analysis.employability_score,
      brutal_roast: analysis.brutal_roast,
      red_flags: redFlags,
      improvement_tips: tips,
      rewritten_summary: analysis.rewritten_summary,
      questions_asked: questions
    }
  }
}];

const agentOutput = $input.first().json.output || '';

// Verifica se o Agent usou a tool (output contém o currículo em JSON)
let curriculo = null;
let done = false;

try {
  const clean = agentOutput.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(clean);
  // Se parseou com sucesso e tem campos do currículo, é o resultado final
  if (parsed.new_summary || parsed.key_skills) {
    curriculo = parsed;
    done = true;
  }
} catch(e) {
  // Não é JSON — ainda está fazendo perguntas
  done = false;
}

return [{
  json: {
    done,
    message: done ? null : agentOutput,
    curriculo: done ? curriculo : null
  }
}];

parameters.responseBody:
={{ JSON.stringify({
  resume_id: $('Code - Valida Body').first().json.resume_id,
  done: $json.done,
  message: $json.message,
  curriculo: $json.curriculo
}) }}

